379:                                 const Http::ResponseHeaderMap& response_headers,
380:                                 Upstream::HostDescriptionOptConstRef upstream_host, bool dropped) {
381:   // Passing the response_status_code explicitly is an optimization to avoid
382:   // multiple calls to slow Http::Utility::getResponseStatus.
383:   ASSERT(response_status_code == Http::Utility::getResponseStatus(response_headers));
384:   if (config_->emit_dynamic_stats_ && !callbacks_->streamInfo().healthCheck()) {
385:     const Http::HeaderEntry* upstream_canary_header = response_headers.EnvoyUpstreamCanary();
386:     const bool is_canary = (upstream_canary_header && upstream_canary_header->value() == "true") ||
387:                            (upstream_host ? upstream_host->canary() : false);
388:     const bool internal_request = Http::HeaderUtility::isEnvoyInternalRequest(*downstream_headers_);
389: 
390:     Stats::StatName upstream_zone = upstreamZone(upstream_host);
391:     Http::CodeStats::ResponseStatInfo info{
392:         config_->scope_,
393:         cluster_->statsScope(),
394:         config_->empty_stat_name_,
395:         response_status_code,
396:         internal_request,
397:         route_->virtualHost()->statName(),
