399:         route_stats_context_.has_value() ? route_stats_context_->statName()
400:                                          : config_->empty_stat_name_,
401:         config_->zone_name_,
402:         upstream_zone,
403:         is_canary};
404: 
405:     Http::CodeStats& code_stats = httpContext().codeStats();
406:     code_stats.chargeResponseStat(info, exclude_http_code_stats_);
407: 
408:     if (alt_stat_prefix_ != nullptr) {
409:       Http::CodeStats::ResponseStatInfo alt_info{config_->scope_,
410:                                                  cluster_->statsScope(),
411:                                                  alt_stat_prefix_->statName(),
412:                                                  response_status_code,
413:                                                  internal_request,
414:                                                  config_->empty_stat_name_,
415:                                                  config_->empty_stat_name_,
416:                                                  config_->empty_stat_name_,
417:                                                  config_->zone_name_,
418:                                                  upstream_zone,
419:                                                  is_canary};
420:       code_stats.chargeResponseStat(alt_info, exclude_http_code_stats_);
421:     }
422: 
423:     if (dropped) {
424:       cluster_->loadReportStats().upstream_rq_dropped_.inc();
425:     }
426:     if (upstream_host && Http::CodeUtility::is5xx(response_status_code)) {
