440: Http::FilterHeadersStatus Filter::decodeHeaders(Http::RequestHeaderMap& headers, bool end_stream) {
441:   downstream_headers_ = &headers;
442: 
443:   // Initialize the `modify_headers_` function that will be used to modify the response headers for
444:   // all upstream responses or local responses.
445:   modify_headers_ = [this](Http::ResponseHeaderMap& headers) {
446:     if (route_entry_ == nullptr) {
447:       return;
448:     }
449: 
450:     if (modify_headers_from_upstream_lb_) {
451:       modify_headers_from_upstream_lb_(headers);
452:     }
453: 
454:     if (attempt_count_ == 0 || !route_entry_->includeAttemptCountInResponse()) {
455:       return;
456:     }
457:     // This header is added without checking for config_->suppress_envoy_headers_ to mirror what
458:     // is done for upstream requests.
459:     headers.setEnvoyAttemptCount(attempt_count_);
460:   };
461: 
462:   // TODO: Maybe add a filter API for this.
463:   grpc_request_ = Grpc::Common::isGrpcRequestHeaders(headers);
464:   exclude_http_code_stats_ = grpc_request_ && config_->suppress_grpc_request_failure_code_stats_;
465: 
466:   // Only increment rq total stat if we actually decode headers here. This does not count requests
467:   // that get handled by earlier filters.
468:   stats_.rq_total_.inc();
469: 
470:   // Determine if there is a route entry or a direct response for the request.
471:   route_ = callbacks_->route();
472:   if (!route_) {
473:     stats_.no_route_.inc();
474:     ENVOY_STREAM_LOG(debug, "no route match for URL '{}'", *callbacks_, headers.getPathValue());
475: 
476:     callbacks_->streamInfo().setResponseFlag(StreamInfo::CoreResponseFlag::NoRouteFound);
477:     callbacks_->sendLocalReply(Http::Code::NotFound, "", nullptr, absl::nullopt,
478:                                StreamInfo::ResponseCodeDetails::get().RouteNotFound);
479:     return Http::FilterHeadersStatus::StopIteration;
480:   }
481: 
482:   // Determine if there is a direct response for the request.
483:   const auto* direct_response = route_->directResponseEntry();
484:   if (direct_response != nullptr) {
485:     stats_.rq_direct_response_.inc();
486:     direct_response->rewritePathHeader(headers, !config_->suppress_envoy_headers_);
487:     std::string body;
488:     absl::string_view direct_response_body = direct_response->formatBody(
489:         (downstream_headers_ == nullptr) ? *Http::StaticEmptyHeaders::get().request_headers
490:                                          : *downstream_headers_,
491:         *Http::StaticEmptyHeaders::get().response_headers, callbacks_->streamInfo(), body);
492: 
493:     callbacks_->sendLocalReply(
494:         direct_response->responseCode(), direct_response_body,
495:         [this, direct_response](Http::ResponseHeaderMap& response_headers) -> void {
496:           std::string new_uri;
497:           ASSERT(downstream_headers_ != nullptr);
498:           if (downstream_headers_->Path()) {
499:             new_uri = direct_response->newUri(*downstream_headers_);
500:           }
501:           // See https://tools.ietf.org/html/rfc7231#section-7.1.2.
502:           const auto add_location =
503:               direct_response->responseCode() == Http::Code::Created ||
504:               Http::CodeUtility::is3xx(enumToInt(direct_response->responseCode()));
505:           if (!new_uri.empty() && add_location) {
506:             response_headers.addReferenceKey(Http::Headers::get().Location, new_uri);
507:           }
508:           const Formatter::Context formatter_context(downstream_headers_, &response_headers, {}, {},
509:                                                      {}, &callbacks_->activeSpan());
510:           direct_response->finalizeResponseHeaders(response_headers, formatter_context,
511:                                                    callbacks_->streamInfo());
512:         },
513:         absl::nullopt, StreamInfo::ResponseCodeDetails::get().DirectResponse);
514:     return Http::FilterHeadersStatus::StopIteration;
515:   }
516: 
517:   // A route entry matches for the request.
518:   route_entry_ = route_->routeEntry();
519:   // Store buffer limits from the route entry.
520:   // The requestBodyBufferLimit() method handles both legacy per_request_buffer_limit_bytes
521:   // and new request_body_buffer_limit configurations automatically.
522:   request_body_buffer_limit_ = route_entry_->requestBodyBufferLimit();
523:   Upstream::ThreadLocalCluster* cluster =
524:       config_->cm_.getThreadLocalCluster(route_entry_->clusterName());
525:   if (!cluster) {
526:     stats_.no_cluster_.inc();
527:     ENVOY_STREAM_LOG(debug, "unknown cluster '{}'", *callbacks_, route_entry_->clusterName());
528: 
529:     callbacks_->streamInfo().setResponseFlag(StreamInfo::CoreResponseFlag::NoClusterFound);
530:     callbacks_->sendLocalReply(route_entry_->clusterNotFoundResponseCode(), "", modify_headers_,
531:                                absl::nullopt,
532:                                StreamInfo::ResponseCodeDetails::get().ClusterNotFound);
533:     return Http::FilterHeadersStatus::StopIteration;
534:   }
535:   cluster_ = cluster->info();
536: 
537:   // Set up stat prefixes, etc.
538:   request_vcluster_ = route_->virtualHost()->virtualCluster(headers);
539:   if (request_vcluster_ != nullptr) {
540:     callbacks_->streamInfo().setVirtualClusterName(request_vcluster_->name());
541:   }
542:   route_stats_context_ = route_entry_->routeStatsContext();
543:   ENVOY_STREAM_LOG(debug, "cluster '{}' match for URL '{}'", *callbacks_,
544:                    route_entry_->clusterName(), headers.getPathValue());
545: 
546:   if (config_->strict_check_headers_ != nullptr) {
547:     for (const auto& header : *config_->strict_check_headers_) {
548:       const auto res = FilterUtility::StrictHeaderChecker::checkHeader(headers, header);
