841:       !transport_socket_options_ || !transport_socket_options_->http11ProxyInfo().has_value();
842:   UpstreamRequestPtr upstream_request = std::make_unique<UpstreamRequest>(
843:       *this, std::move(generic_conn_pool), can_send_early_data, can_use_http3,
844:       allow_multiplexed_upstream_half_close_ /*enable_half_close*/);
845:   LinkedList::moveIntoList(std::move(upstream_request), upstream_requests_);
846:   upstream_requests_.front()->acceptHeadersFromRouter(end_stream);
847:   // Start the shadow streams.
848:   for (const auto& shadow_policy_wrapper : active_shadow_policies_) {
849:     const auto& shadow_policy = shadow_policy_wrapper.get();
850:     const absl::optional<absl::string_view> shadow_cluster_name =
851:         getShadowCluster(shadow_policy, *downstream_headers_);
852:     if (!shadow_cluster_name.has_value()) {
853:       continue;
854:     }
855:     auto shadow_headers = Http::createHeaderMap<Http::RequestHeaderMapImpl>(*shadow_headers_);
856:     applyShadowPolicyHeaders(shadow_policy, *shadow_headers);
857:     const auto options =
858:         Http::AsyncClient::RequestOptions()
859:             .setTimeout(timeout_.global_timeout_)
860:             .setParentSpan(callbacks_->activeSpan())
861:             .setChildSpanName("mirror")
862:             .setSampled(shadow_policy.traceSampled())
863:             .setIsShadow(true)
864:             .setIsShadowSuffixDisabled(shadow_policy.disableShadowHostSuffixAppend())
865:             .setBufferAccount(callbacks_->account())
866:             // Calculate effective buffer limit for shadow streams using the same logic as main
867:             // request. A buffer limit of 1 is set in the case that the effective limit == 0,
868:             // because a buffer limit of zero on async clients is interpreted as no buffer limit.
869:             .setBufferLimit([this]() -> uint64_t {
870:               const uint64_t effective_limit = calculateEffectiveBufferLimit();
871:               return effective_limit == 0 ? 1 : effective_limit;
872:             }())
873:             .setDiscardResponseBody(true)
874:             .setFilterConfig(config_)
875:             .setParentContext(Http::AsyncClient::ParentContext{&callbacks_->streamInfo()});
876:     if (end_stream) {
877:       // This is a header-only request, and can be dispatched immediately to the shadow
878:       // without waiting.
879:       Http::RequestMessagePtr request(new Http::RequestMessageImpl(
880:           Http::createHeaderMap<Http::RequestHeaderMapImpl>(*shadow_headers_)));
881:       applyShadowPolicyHeaders(shadow_policy, request->headers());
882:       config_->shadowWriter().shadow(std::string(shadow_cluster_name.value()), std::move(request),
883:                                      options);
884:     } else {
885:       Http::AsyncClient::OngoingRequest* shadow_stream = config_->shadowWriter().streamingShadow(
886:           std::string(shadow_cluster_name.value()), std::move(shadow_headers), options);
887:       if (shadow_stream != nullptr) {
888:         shadow_streams_.insert(shadow_stream);
889:         shadow_stream->setDestructorCallback(
890:             [this, shadow_stream]() { shadow_streams_.erase(shadow_stream); });
891:         shadow_stream->setWatermarkCallbacks(watermark_callbacks_);
892:       }
893:     }
894:   }
895:   if (end_stream) {
896:     onRequestComplete();
897:   }
898: 
899:   // If this was called due to asynchronous host selection, the caller should continueDecoding.
900:   return true;
901: }
