484: void ConnectionManagerImpl::createCodec(Buffer::Instance& data) {
485:   ASSERT(!codec_);
486:   codec_ = config_->createCodec(read_callbacks_->connection(), data, *this, overload_manager_);
487: 
488:   switch (codec_->protocol()) {
489:   case Protocol::Http3:
490:     stats_.named_.downstream_cx_http3_total_.inc();
491:     stats_.named_.downstream_cx_http3_active_.inc();
492:     break;
493:   case Protocol::Http2:
494:     stats_.named_.downstream_cx_http2_total_.inc();
495:     stats_.named_.downstream_cx_http2_active_.inc();
496:     break;
497:   case Protocol::Http11:
498:   case Protocol::Http10:
499:     stats_.named_.downstream_cx_http1_total_.inc();
500:     stats_.named_.downstream_cx_http1_active_.inc();
